mapper.select:
SELECT cs.id, cs.course_id, ci.course_name, cs.class_id, cl.class_name, cs.week_no, cs.week_day, cs.start_time, cs.end_time, cs.location, cs.latitude, cs.longitude, cs.attendance_radius, cs.auto_publish_attendance FROM course_schedule cs LEFT JOIN course_info ci ON ci.id = cs.course_id LEFT JOIN class_info cl ON cl.id = cs.class_id WHERE 1 = 1
AND cs.course_id = #{courseId}
AND cs.class_id = #{classId}
ORDER BY cs.id DESC
